  "method_chain": [
    {
      "id": "step-01",
      "depends_on": [],
      "step_type": "input_catalog",
      "summary": "Gaia EDR3 astrometry: positions (RA, Dec) and proper motions.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 93,
          "end_line": 93,
          "context": "With proper motions of significantly improved accuracy and precision from the Gaia early data release 3 (EDR3, ...)"
        }
      ]
    },
    {
      "id": "step-02",
      "depends_on": [],
      "step_type": "input_catalog",
      "summary": "Spectroscopic observations from multiple instruments (MMT, LAMOST, SDSS, FEROS, UVES, etc.) used for radial velocities and atmospheric parameters.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 151,
          "end_line": 153,
          "context": "For half of the sample, ... we used our previously published results ... we also carried out quantitative spectral analyses of the remaining targets ..."
        }
      ]
    },
    {
      "id": "step-03",
      "depends_on": [],
      "step_type": "input_catalog",
      "summary": "Ultraviolet, optical, and infrared photometric magnitudes used for spectrophotometric distance via SED fitting.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 153,
          "end_line": 153,
          "context": "The resulting parameters were then used to compute a synthetic spectral energy distribution that was fit to measured magnitudes, which usually cover the ultraviolet, optical, and infrared regime"
        }
      ]
    },
    {
      "id": "step-04",
      "depends_on": [],
      "step_type": "sample_selection",
      "summary": "Target selection: from initial sample of MMT-HVS, Silva+2011 compilation, and individual objects, filter to those with high ejection velocity (mass-dependent threshold: 400 km/s for M<5 Msun, 320 km/s for M>5 Msun) and well-constrained disk origin (1sigma lower limit of galactocentric plane-crossing radius < 25 kpc or visual inspection). Final sample of 30 program stars.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 97,
          "end_line": 97,
          "context": "Based on proper motions from Gaia EDR3, we then carried out spectroscopic and kinematic analyses ... to filter out those with both a high ejection velocity and a relatively well-constrained origin within the Galactic disk."
        }
      ]
    },
    {
      "id": "step-05",
      "depends_on": [
        "step-02"
      ],
      "step_type": "radial_velocity_measurement",
      "summary": "Radial velocities measured from fits of synthetic spectra to observed spectra for all program stars (or adopted from literature for a few stars).",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 153,
          "end_line": 153,
          "context": "Atmospheric parameters such as effective temperature ... surface gravity ... projected rotational velocity ... and radial velocity vrad were determined by fitting the most recent model spectra of appropriate chemical composition to observed spectra."
        }
      ]
    },
    {
      "id": "step-06",
      "depends_on": [
        "step-02"
      ],
      "step_type": "stellar_parameter_inference",
      "summary": "Stellar atmospheric parameters (Teff, log g, v sin i) derived from spectral fitting; stellar masses, radii, luminosities, and evolutionary ages inferred from comparison to Geneva evolutionary tracks.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 153,
          "end_line": 153,
          "context": "Atmospheric parameters ... were determined by fitting ... Stellar masses M and ages tau_evol were inferred by comparing the position of a star in the Kiel diagram to evolutionary tracks by the Geneva group"
        }
      ]
    },
    {
      "id": "step-07",
      "depends_on": [
        "step-02",
        "step-03",
        "step-06"
      ],
      "step_type": "photometric_or_sed_modeling",
      "summary": "Synthetic spectral energy distribution fits to measured photometry to derive angular diameter and interstellar extinction.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 153,
          "end_line": 153,
          "context": "The resulting parameters were then used to compute a synthetic spectral energy distribution that was fit to measured magnitudes ... to derive the angular diameter Theta of the star and the interstellar extinction."
        }
      ]
    },
    {
      "id": "step-08",
      "depends_on": [
        "step-06",
        "step-07"
      ],
      "step_type": "distance_estimation",
      "summary": "Spectrophotometric distance d from solving g = GM/R^2 with R from angular diameter, using the derived stellar mass and surface gravity.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 153,
          "end_line": 153,
          "context": "The spectrophotometric distance d finally followed from solving the definition of the surface gravity, g = GMR^{-2} ... for the stellar radius R and inserting the latter in the definition of the angular diameter, Theta = 2R/d."
        }
      ]
    },
    {
      "id": "step-09",
      "depends_on": [
        "step-01",
        "step-02",
        "step-03",
        "step-04"
      ],
      "step_type": "cross_match",
      "summary": "Cross-match of Gaia EDR3 astrometry with spectroscopic and photometric data to ensure consistent sample.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 97,
          "end_line": 97,
          "context": "Based on proper motions from Gaia EDR3, we then carried out spectroscopic and kinematic analyses ... of all members of this initial sample to filter out those with both a high ejection velocity ..."
        }
      ]
    },
    {
      "id": "step-10",
      "depends_on": [
        "step-01",
        "step-05",
        "step-08"
      ],
      "step_type": "velocity_calculation",
      "summary": "Transformation from observed heliocentric positions, proper motions, radial velocities, and distances to Galactocentric Cartesian positions (x, y, z) and velocities (v_x, v_y, v_z) using assumed solar position and motion (see step-11).",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 157,
          "end_line": 159,
          "context": "The spectrophotometric distances and radial velocities were combined with proper motions from Gaia EDR3 to trace back the trajectories of the program stars to the Galactic plane ..."
        }
      ]
    },
