      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 159,
          "end_line": 159,
          "context": "Uncertainties in the distance of the Sun to the GC and in its relative motion to the local standard of rest (Schönrich et al. 2010) are treated analogously."
        }
