      "summary": "Adopted Milky Way mass model I of Irrgang+2013, a three-component potential (bulge, disk, dark halo), with escape velocity defined from the model.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 159,
          "end_line": 159,
          "context": "To this end, we used the Milky Way mass model I of Irrgang et al. (2013), which is a three-component Galactic potential ..."
        }
      ],
      "parameters": [
        {
          "name": "potential_name",
          "raw_value": "Model I",
          "value": "Model I",
          "source_refs": []
